using System.ComponentModel;
using System.Text.Json;
using ModelContextProtocol.Server;

[McpServerToolType]
public static class ConfigTools
{
    [McpServerTool, Description("Look up a configuration value by key.")]
    public static string GetConfigValue(
        [Description("The configuration key to look up (e.g. 'DatabaseTimeout')")] string key)
    {
        var config = AppConfig.Current;
        return config.TryGetValue(key, out var value)
            ? $"{key} = {value}"
            : $"Key '{key}' not found. Available keys: {string.Join(", ", config.Keys)}";
    }

    [McpServerTool, Description("List all available configuration keys.")]
    public static string ListConfigKeys()
    {
        return string.Join("\n", AppConfig.Current.Keys.Order());
    }
}

using System.ComponentModel;
using System.Text.Json;
using ModelContextProtocol.Server;

[McpServerResourceType]
public static class ConfigResources
{
    [McpServerResource(UriTemplate = "config://app/all", Name = "Full App Configuration",
        MimeType = "application/json"),
     Description("Returns the complete application configuration as JSON.")]
    public static string GetFullConfig() =>
        JsonSerializer.Serialize(AppConfig.Current, AppConfig.JsonOptions);

    [McpServerResource(UriTemplate = "config://app/{section}", Name = "Configuration Section",
        MimeType = "application/json"),
     Description("Returns configuration values for a specific section (database, logging, feature-flags).")]
    public static string GetConfigSection(string section)
    {
        var sectionData = AppConfig.Current
            .Where(kv => kv.Key.StartsWith(section, StringComparison.OrdinalIgnoreCase))
            .ToDictionary(kv => kv.Key, kv => kv.Value);

        return sectionData.Count > 0
            ? JsonSerializer.Serialize(sectionData, AppConfig.JsonOptions)
            : $"No configuration found for section '{section}'.";
    }
}

using System.Text.Json;

/// <summary>
/// Sample in-memory configuration store. Replace with your real config source.
/// </summary>
public static class AppConfig
{
    public static readonly JsonSerializerOptions JsonOptions = new() { WriteIndented = true };

    public static Dictionary<string, string> Current { get; } = new()
    {
        ["DatabaseHost"] = "db.example.com",
        ["DatabasePort"] = "5432",
        ["DatabaseTimeout"] = "30",
        ["LoggingLevel"] = "Information",
        ["LoggingFormat"] = "json",
        ["FeatureFlags.DarkMode"] = "true",
        ["FeatureFlags.BetaApi"] = "false",
    };
}

